class Solution {
    public String reverseParentheses(String s) {
        StringBuilder sb = new StringBuilder();
        Stack<Integer> stack = new Stack<>();
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '(') {
                stack.push(i);
            } else if (s.charAt(i) == ')') {
                int start = stack.pop();
                sb.append(new StringBuilder(s.substring(start + 1, i)).reverse());
            } else {
                sb.append(s.charAt(i));
            }
        }
        return sb.toString();
    }
}
